components.css:
.ds-btn-primary { display: inline-flex; align-items: center; justify-content: center; height: 40px; padding: 0 22px; border-radius: 6px; background: #173a40; color: #f6fefb; border: 1px solid transparent; font-family: "Manrope", ui-sans-serif, system-ui, sans-serif; font-weight: 500; font-size: 14px; line-height: 1; letter-spacing: -0.005em; cursor: pointer; box-shadow: 0 1px 2px rgba(0, 0, 0, 0.06); transition: background-color 180ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 180ms cubic-bezier(0.4, 0, 0.2, 1); white-space: nowrap; }
.ds-btn-primary:hover { background: #0e2a2f; box-shadow: 0 2px 4px rgba(23, 58, 64, 0.12); }
.ds-btn-primary:focus-visible { outline: 2px solid #328f97; outline-offset: 2px; }

.ds-on-dark-frame { display: inline-block; padding: 24px 28px; border-radius: 8px; background: linear-gradient(135deg, #328f97 0%, #2f6a4a 100%); }
.ds-btn-on-dark-primary { display: inline-flex; align-items: center; justify-content: center; height: 40px; padding: 0 22px; border-radius: 6px; background: #f6fefb; color: #173a40; border: 1px solid transparent; font-family: "Manrope", ui-sans-serif, system-ui, sans-serif; font-weight: 500; font-size: 14px; line-height: 1; cursor: pointer; transition: background-color 180ms cubic-bezier(0.4, 0, 0.2, 1); white-space: nowrap; }
.ds-btn-on-dark-primary:hover { background: #ffffff; }
.ds-btn-on-dark-primary:focus-visible { outline: 2px solid #f6fefb; outline-offset: 2px; }

.ds-ghost-frame { display: inline-block; padding: 24px 28px; border-radius: 8px; background: linear-gradient(135deg, #328f97 0%, #2f6a4a 100%); }
.ds-btn-ghost { display: inline-flex; align-items: center; justify-content: center; height: 40px; padding: 0 22px; border-radius: 6px; background: rgba(246, 254, 251, 0.12); color: #f6fefb; border: 1px solid rgba(246, 254, 251, 0.4); font-family: "Manrope", ui-sans-serif, system-ui, sans-serif; font-weight: 500; font-size: 14px; line-height: 1; cursor: pointer; transition: background-color 180ms cubic-bezier(0.4, 0, 0.2, 1), border-color 180ms cubic-bezier(0.4, 0, 0.2, 1); white-space: nowrap; }
.ds-btn-ghost:hover { background: rgba(246, 254, 251, 0.2); border-color: rgba(246, 254, 251, 0.6); }
.ds-btn-ghost:focus-visible { outline: 2px solid #f6fefb; outline-offset: 2px; }

.ds-btn-quiet { display: inline-flex; align-items: center; height: 40px; padding: 0 4px; background: transparent; color: #878787; border: 0; font-family: "Manrope", ui-sans-serif, system-ui, sans-serif; font-weight: 500; font-size: 14px; line-height: 1; text-decoration: none; cursor: pointer; transition: color 180ms cubic-bezier(0.4, 0, 0.2, 1); }
.ds-btn-quiet::after { content: " →"; display: inline-block; margin-left: 4px; transition: transform 180ms cubic-bezier(0.4, 0, 0.2, 1); }
.ds-btn-quiet:hover { color: #252525; }
.ds-btn-quiet:hover::after { transform: translateX(3px); }
.ds-btn-quiet:focus-visible { outline: 2px solid #328f97; outline-offset: 2px; border-radius: 4px; }

.ds-card { padding: 32px 28px 36px; background: #ffffff; border-top: 1px solid rgba(23, 58, 64, 0.16); border-right: 1px solid rgba(23, 58, 64, 0.16); border-bottom: 1px solid rgba(23, 58, 64, 0.16); border-left: 1px solid rgba(23, 58, 64, 0.16); border-radius: 6px; display: flex; flex-direction: column; gap: 14px; transition: background-color 180ms cubic-bezier(0.4, 0, 0.2, 1); max-width: 360px; }
.ds-card:hover { background: #f3faf5; }
.ds-card-eyebrow { font-family: "JetBrains Mono", ui-monospace, monospace; font-weight: 500; font-size: 11px; letter-spacing: 0.08em; text-transform: uppercase; color: #328f97; margin: 0; }
.ds-card-title { font-family: "Inter Tight", "Manrope", ui-sans-serif, sans-serif; font-weight: 700; font-size: 22px; line-height: 1.05; letter-spacing: -0.02em; color: #173a40; margin: 0; }
.ds-card-body { font-family: "Manrope", ui-sans-serif, sans-serif; font-weight: 400; font-size: 14.5px; line-height: 1.6; color: #416166; margin: 0; }
.ds-card-tags { margin-top: auto; padding-top: 18px; border-top: 1px dashed rgba(23, 58, 64, 0.16); display: flex; gap: 6px; flex-wrap: wrap; }
.ds-tag { display: inline-flex; align-items: center; padding: 3px 8px; border-radius: 4px; background: rgba(50, 143, 151, 0.10); color: #328f97; font-family: "JetBrains Mono", ui-monospace, monospace; font-weight: 500; font-size: 11px; letter-spacing: 0.02em; }

.ds-lockup { display: inline-flex; align-items: center; gap: 8px; font-family: "Manrope", ui-sans-serif, sans-serif; font-weight: 600; font-size: 16px; letter-spacing: -0.02em; color: #252525; text-decoration: none; }
.ds-mark { width: 22px; height: 22px; display: block; flex-shrink: 0; transition: transform 8000ms cubic-bezier(0.16, 1, 0.3, 1); }
.ds-lockup:hover .ds-mark { transform: rotate(360deg); }
@media (prefers-reduced-motion: reduce) { .ds-mark { transition: none; } .ds-lockup:hover .ds-mark { transform: none; } }

.ds-dark-frame { display: inline-block; padding: 32px 36px; border-radius: 8px; background: #173a40; }
.ds-lockup-dark { display: inline-flex; align-items: center; gap: 8px; font-family: "Manrope", ui-sans-serif, sans-serif; font-weight: 600; font-size: 16px; letter-spacing: -0.02em; color: #f6fefb; text-decoration: none; }
.ds-lockup-dark .ds-mark { width: 22px; height: 22px; display: block; flex-shrink: 0; transition: transform 8000ms cubic-bezier(0.16, 1, 0.3, 1); }
.ds-lockup-dark:hover .ds-mark { transform: rotate(360deg); }
@media (prefers-reduced-motion: reduce) { .ds-lockup-dark .ds-mark { transition: none; } .ds-lockup-dark:hover .ds-mark { transform: none; } }
